from fastapi import FastAPI
from fastapi.testclient import TestClient
from pydantic import BaseModel

app = FastAPI()

class Item(BaseModel):
    name: str
    price: float

# Store for demonstration
items_db: dict[int, dict] = {}
next_id = 1

@app.get("/items/", tags=["items"], summary="List all items")
def list_items():
    """Retrieve all items from the store."""
    return list(items_db.values())

@app.post("/items/", status_code=201, tags=["items"])
def create_item(item: Item):
    global next_id
    record = {"id": next_id, **item.model_dump()}
    items_db[next_id] = record
    next_id += 1
    return record

@app.get("/items/{item_id}", tags=["items"])
def get_item(item_id: int):
    return items_db.get(item_id, {"error": "not found"})

@app.put("/items/{item_id}", tags=["items"])
def replace_item(item_id: int, item: Item):
    items_db[item_id] = {"id": item_id, **item.model_dump()}
    return items_db[item_id]

@app.delete("/items/{item_id}", status_code=204, tags=["items"])
def delete_item(item_id: int):
    items_db.pop(item_id, None)

client = TestClient(app)

